## 3. 최적화 방안 및 구현 (After)

### 최적화 1: 인덱스 추가 (핵심)

파일 위치: `domain/src/main/kotlin/com/maum/backend/entity/user/UserEntity.kt`

```kotlin
// AFTER - 인덱스 추가
@Entity
@Table(
    catalog = "maum",
    name = "user",
    indexes = [
        // nickname은 unique 제약이 있는 경우 unique index로
        Index(name = "idx_user_nickname", columnList = "nickname", unique = true),
        // 복합 인덱스: status와 함께 조회하는 경우가 많다면 추가
        Index(name = "idx_user_nickname_status", columnList = "nickname, status")
    ]
)
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    @Column(unique = true, nullable = false, length = 30)  // unique 제약으로 자동 unique index
    val nickname: String,

    val phoneNumber: String,
    val gender: Int,
    val birthYear: Int,
    val status: Int,

    @OneToMany(fetch = FetchType.LAZY, mappedBy = "user")
    val profiles: List<ProfileEntity> = emptyList(),

    @OneToMany(fetch = FetchType.LAZY, mappedBy = "user")
    val follows: List<FollowEntity> = emptyList(),

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

Flyway 마이그레이션 파일 위치: `domain/src/main/resources/db/migration/V{버전}__add_user_nickname_index.sql`

```sql
-- AFTER - Flyway 마이그레이션
-- V20260301_001__add_user_nickname_index.sql

-- 기존 데이터 있는 운영 환경: ALGORITHM=INPLACE, LOCK=NONE 으로 무중단 추가
ALTER TABLE maum.user
    ADD UNIQUE INDEX idx_user_nickname (nickname)
    ALGORITHM=INPLACE, LOCK=NONE;
```

인덱스 추가 후 EXPLAIN 결과:

```sql
EXPLAIN SELECT * FROM maum.user WHERE nickname = 'test_user';
-- type: const (unique index 사용 시) 또는 ref
-- rows: 1
-- Extra: Using index
-- 예상 개선: 500ms -> 1ms (500배 향상)
```

### 최적화 2: QueryDSL Projection으로 필요한 컬럼만 조회

파일 위치: `domain/src/main/kotlin/com/maum/backend/repository/user/UserRepository.kt`

```kotlin
// AFTER - Projection DTO + QueryDSL
interface UserRepository : JpaRepository<UserEntity, String>, UserRepositoryCustom {
    fun findByNickname(nickname: String): Optional<UserEntity>

    // 존재 여부만 확인할 때 (닉네임 중복 체크)
    fun existsByNickname(nickname: String): Boolean
}

interface UserRepositoryCustom {
    fun findNicknameProjectionByNickname(nickname: String): UserNicknameProjection?
}
```

파일 위치: `domain/src/main/kotlin/com/maum/backend/repository/user/UserRepositoryCustomImpl.kt`

```kotlin
// AFTER - QueryDSL 구현체: 필요한 필드만 SELECT
@Repository
class UserRepositoryCustomImpl(
    private val queryFactory: JPAQueryFactory,
) : UserRepositoryCustom {

    override fun findNicknameProjectionByNickname(nickname: String): UserNicknameProjection? {
        val user = QUserEntity.userEntity
        return queryFactory
            .select(
                // 전체 엔티티 대신 필요한 필드만 Projection
                Projections.constructor(
                    UserNicknameProjection::class.java,
                    user.id,
                    user.nickname,
                    user.status,
                )
            )
            .from(user)
            .where(user.nickname.eq(nickname))
            .fetchOne()
    }
}

// Projection DTO
data class UserNicknameProjection(
    val id: String,
    val nickname: String,
    val status: Int,
)
```

### 최적화 3: Redis 캐싱 전략

파일 위치: `api/src/main/kotlin/com/maum/backend/service/user/UserService.kt`

```kotlin
// AFTER - Redis 캐시 적용
@Service
class UserService(
    private val userRepository: UserRepository,
    private val redisTemplate: RedisTemplate<String, UserNicknameProjection>,
) {
    companion object {
        private const val CACHE_KEY_PREFIX = "user:nickname:"
        private const val CACHE_TTL_SECONDS = 300L  // 5분 TTL
    }

    // BEFORE: 캐시 없이 매번 DB 조회
    // fun findByNickname(nickname: String): UserNicknameProjection? {
    //     return userRepository.findNicknameProjectionByNickname(nickname)
    // }

    // AFTER: Redis 캐시 적용
    fun findByNickname(nickname: String): UserNicknameProjection? {
        val cacheKey = "$CACHE_KEY_PREFIX$nickname"

        // 1. 캐시에서 먼저 조회
        val cached = redisTemplate.opsForValue().get(cacheKey)
        if (cached != null) return cached

        // 2. 캐시 미스 시 DB 조회
        val user = userRepository.findNicknameProjectionByNickname(nickname)
            ?: return null

        // 3. 캐시에 저장 (TTL 5분)
        redisTemplate.opsForValue().set(cacheKey, user, CACHE_TTL_SECONDS, TimeUnit.SECONDS)
        return user
    }

    // 닉네임 변경 시 캐시 무효화
    fun updateNickname(userId: String, newNickname: String) {
        val user = userRepository.findById(userId).orElseThrow()
        val oldCacheKey = "$CACHE_KEY_PREFIX${user.nickname}"

        // DB 업데이트
        // ... 업데이트 로직

        // 캐시 무효화
        redisTemplate.delete(oldCacheKey)
    }
}
```

`@Cacheable` 어노테이션 방식 대안 (Spring Cache 추상화):

```kotlin
// AFTER - Spring Cache 추상화 방식 (더 선언적)
@Service
class UserService(
    private val userRepository: UserRepository,
) {
    @Cacheable(
        cacheNames = ["user-by-nickname"],
        key = "#nickname",
        unless = "#result == null"  // null은 캐시하지 않음
    )
    fun findByNickname(nickname: String): UserNicknameProjection? {
        return userRepository.findNicknameProjectionByNickname(nickname)
    }

    @CacheEvict(cacheNames = ["user-by-nickname"], key = "#oldNickname")
    fun updateNickname(userId: String, oldNickname: String, newNickname: String) {
        // 업데이트 로직
    }
}
```

Redis 캐시 설정 파일 위치: `api/src/main/kotlin/com/maum/backend/config/CacheConfig.kt`

```kotlin
// AFTER - Redis 캐시 설정
@Configuration
@EnableCaching
class CacheConfig {

    @Bean
    fun cacheManager(redisConnectionFactory: RedisConnectionFactory): CacheManager {
        val config = RedisCacheConfiguration.defaultCacheConfig()
            .entryTtl(Duration.ofMinutes(5))           // 기본 TTL 5분
            .serializeKeysWith(
                RedisSerializationContext.SerializationPair.fromSerializer(StringRedisSerializer())
            )
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(
                    GenericJackson2JsonRedisSerializer()
                )
            )
            .disableCachingNullValues()                // null 캐싱 방지

        val cacheConfigurations = mapOf(
            "user-by-nickname" to config.entryTtl(Duration.ofMinutes(5)),
        )

        return RedisCacheManager.builder(redisConnectionFactory)
            .cacheDefaults(config)
            .withInitialCacheConfigurations(cacheConfigurations)
            .build()
    }
}
```

