        val user = userRepository.findNicknameProjectionByNickname(nickname)
            ?: return null

        // 3. 캐시에 저장 (TTL 5분)
        redisTemplate.opsForValue().set(cacheKey, user, CACHE_TTL_SECONDS, TimeUnit.SECONDS)
        return user
    }

